```typescript
// frontend/src/utils/contrastCheck.ts
// WCAG 2.1 相对亮度公式 + 对比度计算 + 全调色板审计

export function hexToRgb(hex: string): [number, number, number] {
  // 支持 6-digit (#F5F1EA), 3-digit (#FFF), 无 # 前缀
  const h = hex.replace(/^#/, '');
  if (h.length === 3) {
    return [
      parseInt(h[0] + h[0], 16),
      parseInt(h[1] + h[1], 16),
      parseInt(h[2] + h[2], 16),
    ];
  }
  return [
    parseInt(h.slice(0, 2), 16),
    parseInt(h.slice(2, 4), 16),
    parseInt(h.slice(4, 6), 16),
  ];
}

function srgbLinearize(channel: number): number {
  const s = channel / 255;
  return s <= 0.03928 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4);
}

export function relativeLuminance(r: number, g: number, b: number): number {
  // L = 0.2126 * R + 0.7152 * G + 0.0722 * B
  return (
    0.2126 * srgbLinearize(r) +
    0.7152 * srgbLinearize(g) +
    0.0722 * srgbLinearize(b)
  );
}

export function getContrastRatio(hex1: string, hex2: string): number {
  const [r1, g1, b1] = hexToRgb(hex1);
  const [r2, g2, b2] = hexToRgb(hex2);
  const l1 = relativeLuminance(r1, g1, b1) + 0.05;
  const l2 = relativeLuminance(r2, g2, b2) + 0.05;
  return Math.max(l1, l2) / Math.min(l1, l2);
}

export function checkWCAG_AA(
  hex1: string, hex2: string, isLargeText = false
): boolean {
  const ratio = getContrastRatio(hex1, hex2);
  return isLargeText ? ratio >= 3.0 : ratio >= 4.5;
}

export interface ContrastReport {
  foreground: string;
  background: string;
  ratio: number;
  pass: boolean;
  usage: string;
}

export function auditColorPalette(colors: Record): ContrastReport[] {
  // 遍历所有 (fg, bg) 组合，返回 PASS/FAIL 报告
  // 预定义关键色彩对: [fg_name, bg_name, isLargeText, usage]
}
