prompt.color_adapt_code:
```typescript
// frontend/src/utils/colorAdapt.ts

type TimePeriod = 'night' | 'day';

export function getTimePeriod(): TimePeriod {
  const hour = new Date().getHours();
  return (hour >= 20 || hour < 6) ? 'night' : 'day';
}

export function getColorTemperatureShift(): { warmth: number; label: string } {
  const period = getTimePeriod();
  return period === 'night'
    ? { warmth: 0.05, label: '2700K-3000K' }  // 暖色偏移 +5%
    : { warmth: 0, label: '4000K-5000K' };     // 基准色温
}

export function applyColorAdaptation(): void {
  const shift = getColorTemperatureShift();
  document.documentElement.style.setProperty(
    '--color-warmth-shift', String(shift.warmth)
  );
}
```
